// ★カットのプロンプトを書いてください（最大15カット）
// newScene: true → T2I（シーン切り替え）
// newScene省略 → I2I（前カット参照）
const cuts = [
  {
    prompt: 'RAW photo, a small fox kit sitting in autumn leaves, golden hour lighting, shallow depth of field, hyperrealistic wildlife photography',
    newScene: true
  },
  {
    prompt: 'The same scene. Now the fox kit stands up and sniffs the air, ears perked forward.'
  }
];
return [{ json: { cuts, index: 0 } }];

const state = $input.first().json;
const { cuts, index } = state;
const cut = cuts[index];
if (!cut) throw new Error(`index ${index} が範囲外 (total: ${cuts.length})`);

const isT2I = (index === 0) || !!cut.newScene;
const prevFilename = isT2I ? null : `cut_${String(index).padStart(2, '0')}.png`;
if (!isT2I && !prevFilename) throw new Error(`cut${index+1}: 前ファイル名なし`);

const seed = Math.floor(Math.random() * 999999999999);
const wf = {};
if (isT2I) {
  wf['77:61'] = { inputs: { sampler_name: 'euler' }, class_type: 'KSamplerSelect' };
  wf['77:62'] = { inputs: { steps: 6, width: 720, height: 1280 }, class_type: 'Flux2Scheduler' };
  wf['77:63'] = { inputs: { cfg: 1, model: ['77:70', 0], positive: ['77:74', 0], negative: ['77:76', 0] }, class_type: 'CFGGuider' };
  wf['77:64'] = { inputs: { noise: ['77:73', 0], guider: ['77:63', 0], sampler: ['77:61', 0], sigmas: ['77:62', 0], latent_image: ['77:66', 0] }, class_type: 'SamplerCustomAdvanced' };
  wf['77:65'] = { inputs: { samples: ['77:64', 0], vae: ['77:72', 0] }, class_type: 'VAEDecode' };
  wf['77:66'] = { inputs: { width: 720, height: 1280, batch_size: 1 }, class_type: 'EmptyFlux2LatentImage' };
  wf['77:70'] = { inputs: { unet_name: 'flux-2-klein-9b.safetensors', weight_dtype: 'default' }, class_type: 'UNETLoader' };
  wf['77:71'] = { inputs: { clip_name: 'qwen_3_8b.safetensors', type: 'flux2', device: 'default' }, class_type: 'CLIPLoader' };
  wf['77:72'] = { inputs: { vae_name: 'flux2-vae.safetensors' }, class_type: 'VAELoader' };
  wf['77:73'] = { inputs: { noise_seed: seed }, class_type: 'RandomNoise' };
  wf['77:74'] = { inputs: { text: cut.prompt, clip: ['77:71', 0] }, class_type: 'CLIPTextEncode' };
  wf['77:76'] = { inputs: { conditioning: ['77:74', 0] }, class_type: 'ConditioningZeroOut' };
  wf['78']    = { inputs: { filename_prefix: 'Flux2-Klein-T2I', images: ['77:65', 0] }, class_type: 'SaveImage' };
} else {
  // Kontext I2I: ReferenceLatentでキャラ一貫性を保ちながら新シーン生成
  wf['76']       = { inputs: { image: prevFilename }, class_type: 'LoadImage' };
  wf['75:80']    = { inputs: { upscale_method: 'nearest-exact', megapixels: 1, resolution_steps: 1, image: ['76', 0] }, class_type: 'ImageScaleToTotalPixels' };
  wf['75:81']    = { inputs: { image: ['75:80', 0] }, class_type: 'GetImageSize' };
  wf['75:66']    = { inputs: { width: ['75:81', 0], height: ['75:81', 1], batch_size: 1 }, class_type: 'EmptyFlux2LatentImage' };
  wf['75:79:78'] = { inputs: { pixels: ['75:80', 0], vae: ['75:72', 0] }, class_type: 'VAEEncode' };
  wf['75:74']    = { inputs: { text: cut.prompt, clip: ['75:71', 0] }, class_type: 'CLIPTextEncode' };
  wf['75:82']    = { inputs: { conditioning: ['75:74', 0] }, class_type: 'ConditioningZeroOut' };
  wf['75:79:77'] = { inputs: { conditioning: ['75:74', 0], latent: ['75:79:78', 0] }, class_type: 'ReferenceLatent' };
  wf['75:79:76'] = { inputs: { conditioning: ['75:82', 0], latent: ['75:79:78', 0] }, class_type: 'ReferenceLatent' };
  wf['75:61']    = { inputs: { sampler_name: 'euler' }, class_type: 'KSamplerSelect' };
  wf['75:62']    = { inputs: { steps: 6, width: ['75:81', 0], height: ['75:81', 1] }, class_type: 'Flux2Scheduler' };
  wf['75:63']    = { inputs: { cfg: 1, model: ['75:70', 0], positive: ['75:79:77', 0], negative: ['75:79:76', 0] }, class_type: 'CFGGuider' };
  wf['75:73']    = { inputs: { noise_seed: seed }, class_type: 'RandomNoise' };
  wf['75:64']    = { inputs: { noise: ['75:73', 0], guider: ['75:63', 0], sampler: ['75:61', 0], sigmas: ['75:62', 0], latent_image: ['75:66', 0] }, class_type: 'SamplerCustomAdvanced' };
  wf['75:70']    = { inputs: { unet_name: 'flux-2-klein-9b.safetensors', weight_dtype: 'default' }, class_type: 'UNETLoader' };
  wf['75:71']    = { inputs: { clip_name: 'qwen_3_8b.safetensors', type: 'flux2', device: 'default' }, class_type: 'CLIPLoader' };
  wf['75:72']    = { inputs: { vae_name: 'flux2-vae.safetensors' }, class_type: 'VAELoader' };
  wf['75:65']    = { inputs: { samples: ['75:64', 0], vae: ['75:72', 0] }, class_type: 'VAEDecode' };
  wf['9']        = { inputs: { filename_prefix: 'Flux2-Klein-Kontext', images: ['75:65', 0] }, class_type: 'SaveImage' };
}
// workflowのみ返す（stateはSave StateノードでBuild Workflowから再取得）
return [{ json: { cuts, index, workflow: wf } }];

// Submit ImageのレスポンスからPrompt IDを取得
const promptId = $input.first().json.prompt_id;
if (!promptId) throw new Error('prompt_idが取得できません: ' + JSON.stringify($input.first().json));
// Build WorkflowノードからStateを復元（最新実行の結果）
const { cuts, index } = $('Build Workflow').first().json;
return [{ json: { cuts, index, prompt_id: promptId } }];

const history = $input.first().json;
// Save StateノードからStateを復元（最新実行の結果）
const state = $('Save State').first().json;
const { prompt_id, cuts, index } = state;

const entry = history[prompt_id];
if (!entry?.status?.completed) {
  return [{ json: { ...state, done: false } }];
}

const outputs = entry.outputs;
const nodeKey = Object.keys(outputs)[0];
const img = outputs[nodeKey]?.images?.[0];
if (!img) throw new Error('cut' + (index + 1) + ': outputs内に画像なし');

return [{ json: { ...state, done: true, filename: img.filename, subfolder: img.subfolder || '' } }];

const item = $input.first();
const { index } = $('Check Done').first().json;
const filename = `cut_${String(index + 1).padStart(2, '0')}.png`;
return [{
  json: item.json,
  binary: {
    data: {
      ...item.binary.data,
      fileName: filename,
      mimeType: 'image/png'
    }
  }
}];
